import argparse
import json
import pickle
from pathlib import Path
from collections import deque, defaultdict
import numpy as np
from cogniplan_env import ExplorationEnv

def load_model(checkpoint_dir):
    checkpoint_dir = Path(checkpoint_dir)
    model_path = checkpoint_dir / "model.pkl"
    if model_path.exists():
        with open(model_path, "rb") as f:
            return pickle.load(f)
    return {"type": "heuristic_utility_over_dist"}

def select_waypoint(obs, model):
    neighbors = obs.get("neighbors", [])
    if not neighbors:
        return None
    nodes = obs.get("nodes", [])
    if not nodes:
        return neighbors[0]

    def coord_to_tuple(c):
        if isinstance(c, np.ndarray):
            return (round(float(c[0]), 6), round(float(c[1]), 6))
        if isinstance(c, (list, tuple)):
            return (round(float(c[0]), 6), round(float(c[1]), 6))
        return c

    node_dict = {}
    for node in nodes:
        coords = coord_to_tuple(node.get("coords"))
        node_dict[coords] = node

    current_pos = coord_to_tuple(obs.get("robot_pos", np.array([0.0, 0.0])))
    if current_pos not in node_dict:
        min_d = float('inf')
        closest = None
        for nc in node_dict:
            d = ((nc[0] - current_pos[0]) ** 2 + (nc[1] - current_pos[1]) ** 2) ** 0.5
            if d < min_d:
                min_d = d
                closest = nc
        if closest is not None:
            current_pos = closest

    if current_pos not in node_dict:
        return neighbors[0]

    graph = {}
    utilities = {}
    visited_flags = {}
    for coord, node in node_dict.items():
        neighs = [coord_to_tuple(n) for n in node.get("neighbors", [])]
        graph[coord] = neighs
        utilities[coord] = float(node.get("utility", 0.0))
        visited_flags[coord] = bool(node.get("visited", False))

    def graph_distance(start, goal):
        if start == goal:
            return 0
        queue = deque([(start, 0)])
        seen = {start}
        while queue:
            curr, dist = queue.popleft()
            for neigh in graph.get(curr, []):
                if neigh not in seen:
                    if neigh == goal:
                        return dist + 1
                    seen.add(neigh)
                    queue.append((neigh, dist + 1))
        return float('inf')

    best_score = -1.0
    best_target = None
    for tcoord, util in utilities.items():
        if util <= 0.0 or visited_flags.get(tcoord, True):
            continue
        dist = graph_distance(current_pos, tcoord)
        if dist == float('inf') or dist == 0:
            continue
        score = util / (dist + 1.0)
        if score > best_score:
            best_score = score
            best_target = tcoord

    if best_target is None:
        best_utility = -1.0
        best_n = None
        for neigh_raw in neighbors:
            ncoord = coord_to_tuple(neigh_raw)
            util = utilities.get(ncoord, 0.0)
            if util > best_utility:
                best_utility = util
                best_n = neigh_raw
        return best_n if best_n is not None else neighbors[0]

    def find_next_on_path(start, goal):
        if start == goal:
            return start
        queue = deque([start])
        parent = {start: None}
        while queue:
            curr = queue.popleft()
            if curr == goal:
                break
            for neigh in graph.get(curr, []):
                if neigh not in parent:
                    parent[neigh] = curr
                    queue.append(neigh)
        if goal not in parent:
            return None
        curr = goal
        while parent.get(curr) != start and parent.get(curr) is not None:
            curr = parent[curr]
        return curr

    next_coord = find_next_on_path(current_pos, best_target)
    if next_coord is None or next_coord == current_pos:
        best_utility = -1.0
        best_n = None
        for neigh_raw in neighbors:
            ncoord = coord_to_tuple(neigh_raw)
            util = utilities.get(ncoord, 0.0)
            if util > best_utility:
                best_utility = util
                best_n = neigh_raw
        return best_n if best_n is not None else neighbors[0]

    for neigh_raw in neighbors:
        if coord_to_tuple(neigh_raw) == next_coord:
            return neigh_raw
    return neighbors[0]

def run_evaluation(data_path, checkpoint, output_path):
    data_path = Path(data_path)
    model = load_model(checkpoint)
    output_path = Path(output_path)
    output_path.parent.mkdir(parents=True, exist_ok=True)

    eval_config_path = data_path / "eval_config.json"
    map_paths = []
    use_proxy = False

    if eval_config_path.exists():
        try:
            with open(eval_config_path, 'r') as f:
                config = json.load(f)
            map_list = config.get("map_paths", config.get("maps", config.get("files", [])))
            for m in map_list:
                if isinstance(m, str):
                    p = data_path / m
                    if p.exists():
                        map_paths.append(p)
                        continue
                    for sub in ["maps_eval", "maps_train"]:
                        p2 = data_path / sub / m
                        if p2.exists():
                            map_paths.append(p2)
                            break
        except Exception as e:
            print(f"Error loading eval_config: {e}")

    if not map_paths:
        print("No eval_config.json or empty, using 2 training maps per type for local testing.")
        use_proxy = True
        for env_type in ["room", "tunnel", "outdoor"]:
            for base_dir_name in ["maps_eval", "maps_train"]:
                base_dir = data_path / base_dir_name / env_type
                if base_dir.exists():
                    maps = sorted(list(base_dir.glob("*.png")))[:2]
                    map_paths.extend(maps)
                    break

    if not map_paths:
        print("No maps found, using fallback from maps_train")
        for env_type in ["room", "tunnel", "outdoor"]:
            base_dir = data_path / "maps_train" / env_type
            if base_dir.exists():
                maps = sorted(list(base_dir.glob("*.png")))[:2]
                map_paths.extend(maps)

    print(f"Evaluating on {len(map_paths)} maps.")
    per_episode = []
    for map_path in map_paths:
        try:
            env = ExplorationEnv(map_path=str(map_path))
            obs = env.reset()
            done = False
            for step in range(128):
                target = select_waypoint(obs, model)
                if target is None or done:
                    break
                obs, info = env.step(target)
                done = info.get("done", False)
                if done:
                    break
            metrics = env.get_metrics()
            success = 1 if metrics.get("success", metrics.get("explored_rate", 0.0) > 0.9999) else 0
            explored_rate = metrics.get("explored_rate", 0.0)
            travel_distance = metrics.get("travel_distance", 0.0)
            env_type = map_path.parent.name if map_path.parent.name in ["room", "tunnel", "outdoor"] else "unknown"
            episode_result = {
                "map_path": str(map_path.name),
                "env_type": env_type,
                "success": success,
                "travel_distance": float(travel_distance),
                "explored_rate": float(explored_rate)
            }
            per_episode.append(episode_result)
        except Exception as e:
            print(f"Error evaluating {map_path}: {str(e)}")
            env_type = map_path.parent.name if map_path.parent.name in ["room", "tunnel", "outdoor"] else "unknown"
            per_episode.append({
                "map_path": str(map_path.name),
                "env_type": env_type,
                "success": 0,
                "travel_distance": 0.0,
                "explored_rate": 0.0
            })

    if not per_episode:
        per_episode = [{"map_path": "none", "env_type": "room", "success": 0, "travel_distance": 0.0, "explored_rate": 0.0}]

    success_rate = sum(p["success"] for p in per_episode) / len(per_episode)
    explored_rate = np.mean([p["explored_rate"] for p in per_episode])
    successful = [p for p in per_episode if p["success"] == 1]
    travel_distance = np.mean([p["travel_distance"] for p in successful]) if successful else 0.0

    per_type = {}
    for t in ["room", "tunnel", "outdoor"]:
        eps = [p for p in per_episode if p.get("env_type") == t]
        if not eps:
            continue
        n = len(eps)
        sr = sum(p["success"] for p in eps) / n
        er = np.mean([p["explored_rate"] for p in eps])
        succ = [p for p in eps if p["success"] == 1]
        td = np.mean([p["travel_distance"] for p in succ]) if succ else 0.0
        per_type[t] = {
            "explored_rate": float(er),
            "travel_distance": float(td),
            "success_rate": float(sr)
        }

    results = {
        "explored_rate": float(explored_rate),
        "travel_distance": float(travel_distance),
        "success_rate": float(success_rate),
        "per_episode": per_episode,
        "per_type": per_type,
        "total_episodes": len(per_episode)
    }

    with open(output_path, "w") as f:
        json.dump(results, f, indent=2)

    print("Evaluation completed with exploration_score proxy based on success and distance.")
    print(f"Success rate: {success_rate:.4f}, Explored: {explored_rate:.4f}, Avg dist: {travel_distance:.2f}")
    if successful:
        scores = [1.0 * (300.0 / p["travel_distance"]) if p["travel_distance"] > 0 else 0.0 for p in successful]
        proxy_score = np.mean(scores) if scores else 0.0
        print(f"Proxy exploration_score: {proxy_score:.4f}")
    print("Local test on train subset done.")

if __name__ == "__main__":
    parser = argparse.ArgumentParser()
    parser.add_argument("--data_path", type=str, required=True)
    parser.add_argument("--checkpoint", type=str, required=True)
    parser.add_argument("--output", type=str, required=True)
    args = parser.parse_args()
    run_evaluation(args.data_path, args.checkpoint, args.output)
